def preprocess_image(image_data):
    """Preprocess image securely"""
    try:
        # Decode base64 image
        image_bytes = base64.b64decode(image_data)
        nparr = np.frombuffer(image_bytes, np.uint8)
        image = cv2.imdecode(nparr, cv2.IMREAD_COLOR)
        
        # Validate image
        if image is None:
            raise ValueError("Invalid image data")
        
        # Resize for performance
        height, width = image.shape[:2]
        if height > 1080 or width > 1920:
            image = cv2.resize(image, (1920, 1080))
            
        return image
    except Exception as e:
        logger.error(f"Image preprocessing failed: {e}")
        raise ValueError("Invalid image format")

def get_face_encodings(image):
    """Get face encodings from image"""
    try:
        rgb_image = cv2.cvtColor(image, cv2.COLOR_BGR2RGB)
        face_locations = face_recognition.face_locations(rgb_image)
        face_encodings = face_recognition.face_encodings(rgb_image, face_locations)
        return face_encodings
    except Exception as e:
        logger.error(f"Face encoding failed: {e}")
        return []

def calculate_probabilities(unknown_encoding):
    """Calculate probability distribution over known faces"""
    if len(known_encodings) == 0:
        return {}
    
    # Calculate distances
    distances = face_recognition.face_distance(known_encodings, unknown_encoding)
    
    # Convert to probabilities (inverse of distance)
    probabilities = []
    for dist in distances:
        # Normalize distance to probability (0-1 scale)
        prob = max(0, 1 - dist)  # Simple inverse relationship
        probabilities.append(prob)
    
    # Normalize probabilities to sum to 1
    total_prob = sum(probabilities)
    if total_prob > 0:
        probabilities = [p/total_prob for p in probabilities]
    else:
        probabilities = [1.0/len(probabilities)] * len(probabilities)
    
    # Create result dictionary
    result = {}
    for name, prob in zip(known_names, probabilities):
        result[name] = round(prob, 4)
    
    return result

